commit 4c1cfd5a0e2ecce02735cda985c60d6902b97824
Author: igs-jiunchiwang <jiunchiwang@igs.com.tw>
Date:   Fri Jul 10 15:39:55 2026 +0800

    feat(preamble): 借鏡 fable-advisor 強化 delegate goal prompt 指引

    - RELAY_DELEGATE / PARALLEL_DELEGATE 三要素 → 五要素
      （加「已知背景」「待決問題」，減少 delegate 從零探索）
    - PARALLEL_DELEGATE 加 context 模式指引（決策型 brief vs 調查型 investigation）
    - 兩處加結果權重協議（給認真權重；僅經驗性失敗或一手資料矛盾時不採納）

    靈感來源：echo-of-machines/fable-advisor 的 focused-brief context packaging pattern

    Co-Authored-By: Claude Opus 4.6 (1M context) <noreply@anthropic.com>

diff --git a/src/memory.ts b/src/memory.ts
index 50fabd6..78a163c 100644
--- a/src/memory.ts
+++ b/src/memory.ts
@@ -598,7 +598,13 @@ function buildRelayDelegateNote(): string {
   note += "- 純文字格式（推薦）：`<<RELAY_DELEGATE:peer|任務描述>>`\n";
   note += "- JSON 格式（需要帶 context/maxTurns 時）：`<<RELAY_DELEGATE:peer|{\"id\":\"rd_xxx\",\"goal\":\"...\",\"context\":\"...\"}>>` \n";
   note += "- goal/prompt 不可含 `>>` 或 `|`\n";
-  note += "- goal 應含三要素：目標與動機 / 驗收條件 / 回報格式（只回結論+檔案:行號，長產物存檔回傳路徑）\n";
+  note += "- goal 應含五要素：\n";
+  note += "  1. 目標與動機（為什麼委派）\n";
+  note += "  2. 已知背景（你已掌握的事實、已嘗試的方案、關鍵證據——不要讓 delegate 從零開始）\n";
+  note += "  3. 待決問題（具體要 delegate 回答或產出什麼）\n";
+  note += "  4. 驗收條件\n";
+  note += "  5. 回報格式（只回結論+檔案:行號，長產物存檔回傳路徑）\n";
+  note += "- 結果回來後：給 delegate 結論認真權重（獨立視角）；僅在經驗性失敗或一手資料矛盾時才不採納；整合後簡要告知使用者\n";
   note += "- 不要等結果——發出後正常回覆使用者「已委派」即可\n";
   note += "- ⚠️ 重要：發 RELAY_DELEGATE 的 turn 必須包含至少一個 tool call（如 list_facts），否則 token 會被 CLI 吞掉不送出\n";
   note += "[End tool]\n\n";
@@ -644,9 +650,14 @@ function buildParallelDelegateNote(): string {
   note += "格式規則：\n";
   note += "- task_id：唯一識別碼（如 `pt_1`、`pt_2`）\n";
   note += "- specialist_name：目標 specialist（同一個 name 可以開多個 instance）\n";
-  note += "- goal prompt：任務描述（不可含 `>>` 或 `|`），同樣應含三要素：目標與動機 / 驗收條件 / 回報格式\n";
+  note += "- goal prompt：任務描述（不可含 `>>` 或 `|`），應含五要素：\n";
+  note += "  1. 目標與動機 2. 已知背景（已掌握的事實/證據） 3. 待決問題 4. 驗收條件 5. 回報格式\n";
+  note += "- context 模式選擇：\n";
+  note += "  - 決策型（方案取捨/設計判斷）：自己打包 context brief 進 goal，精簡但完整\n";
+  note += "  - 調查型（code review/跨檔驗證）：goal 裡給檔案路徑+問題，讓 specialist 自己讀 code 調查\n";
   note += "- 每個 task 獨立 instance，互不干擾——但要避免多個 task 改同一個檔案\n";
-  note += "- ⚠️ 同樣需要至少一個 tool call 防止 CLI 吞 token\n\n";
+  note += "- ⚠️ 同樣需要至少一個 tool call 防止 CLI 吞 token\n";
+  note += "- 結果回來後：給 delegate 結論認真權重（獨立視角）；僅在經驗性失敗或一手資料矛盾時才不採納；整合後簡要告知使用者\n\n";
   note += "使用時機：任務可拆成多個獨立子任務且各自耗時 > 1 分鐘（如同時研究多支影片、同時改不同模組）。\n";
   note += "單一任務用 RELAY_DELEGATE；可並行的多任務用 PARALLEL_DELEGATE。\n";
   note += "[End tool]\n\n";

